mapper.select:
SELECT id AS id, title AS title, category AS category, source AS source, content AS content, keywords AS keywords, priority AS priority, enabled AS enabled, gmt_create AS gmtCreate, gmt_modified AS gmtModified FROM knowledge_chunk WHERE 1 = 1
AND category = #{category}
AND enabled = #{enabled}
AND ( title LIKE '%' || #{keyword} || '%' OR content LIKE '%' || #{keyword} || '%' OR keywords LIKE '%' || #{keyword} || '%' OR source LIKE '%' || #{keyword} || '%' )
ORDER BY priority DESC, gmt_modified DESC LIMIT #{limit}

mapper.update:
UPDATE knowledge_chunk
SET
enabled = #{enabled},
gmt_modified = #{gmtModified}
WHERE id = #{id}
